    val applicationStatus = enumOf(name = "ApplicationStatus") {
        literal(name = "PENDING")
        literal(name = "REVIEWED")
        literal(name = "ACCEPTED")
        literal(name = "REJECTED")
    }
    val memberStatus = enumOf(name = "MemberStatus") {
        literal(name = "ACTIVE")
        literal(name = "PASSIVE")
        literal(name = "RESIGNED")
    }
    val notifiable = interfaceOf(name = "Notifiable") {
        operation(name = "notify") {
            parameter(name = "message", type = "String")
            returns(typeName = "Boolean")
        }
    }
    val stateChapter = classOf(name = "StateChapter") {
        attribute(name = "name", type = "String")
        attribute(name = "state", type = "String")
    }
    val districtChapter = classOf(name = "DistrictChapter") {
        attribute(name = "name", type = "String")
        attribute(name = "region", type = "String")
    }
    val member = classOf(name = "Member") {
        implements(iface = notifiable)
        attribute(name = "memberNumber", type = "String", isReadOnly = true)
        attribute(name = "name", type = "String")
        attribute(name = "joinDate", type = "LocalDate")
        attribute(name = "status", type = memberStatus, defaultValue = "ACTIVE")
    }
    val membershipApplication = classOf(name = "MembershipApplication") {
        attribute(name = "receiptDate", type = "LocalDate")
        attribute(name = "status", type = applicationStatus, defaultValue = "PENDING")
    }
    val committee = classOf(name = "Committee") {
        attribute(name = "name", type = "String")
        attribute(name = "level", type = "String")
    }
    val committeeMandate = classOf(name = "CommitteeMandate") {
        attribute(name = "role", type = "String")
        attribute(name = "termStart", type = "LocalDate")
        attribute(name = "termEnd", type = "LocalDate")
    }
    val campaign = classOf(name = "Campaign") {
        attribute(name = "name", type = "String")
        attribute(name = "budget", type = "BigDecimal")
    }
    val campaignDeployment = classOf(name = "CampaignDeployment") {
        attribute(name = "date", type = "LocalDate")
        attribute(name = "hours", type = "Double")
    }
    val payment = classOf(name = "Payment") {
        isAbstract = true
        attribute(name = "amount", type = "BigDecimal")
        attribute(name = "date", type = "LocalDate")
    }
    val membershipFeePayment = classOf(name = "MembershipFeePayment") {
        extends(general = payment)
        attribute(name = "contributionYear", type = "Int")
    }
    val donation = classOf(name = "Donation") {
        extends(general = payment)
        attribute(name = "receiptRequested", type = "Boolean", defaultValue = "false")
    }
    association(source = stateChapter, target = districtChapter) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "1..*"); role = "districts" }
    }
    association(source = districtChapter, target = member) {
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "0..*"); role = "members" }
    }
    association(source = membershipApplication, target = districtChapter) {
        source { multiplicity(spec = "0..*") }
        target { multiplicity(spec = "1"); role = "submittedTo" }
    }
    association(source = committee, target = committeeMandate) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "0..*"); role = "mandates" }
    }
    association(source = committeeMandate, target = member) {
        source { multiplicity(spec = "0..*") }
        target { multiplicity(spec = "1") }
    }
    association(source = campaign, target = districtChapter) {
        source { multiplicity(spec = "0..*") }
        target { multiplicity(spec = "1") }
    }
    association(source = campaign, target = campaignDeployment) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "0..*"); role = "deployments" }
    }
    association(source = campaignDeployment, target = member) {
        source { multiplicity(spec = "0..*") }
        target { multiplicity(spec = "1") }
    }
    association(source = payment, target = member) {
        source { multiplicity(spec = "0..*") }
        target { multiplicity(spec = "1"); role = "payer" }
    }
    association(source = donation, target = campaign) {
        source { multiplicity(spec = "0..*") }
        target { multiplicity(spec = "0..1"); role = "earmarkedFor" }
    }
    dependency(client = member, supplier = membershipApplication, name = "derivedFrom")
}

