sequenceDiagram(name = "Online Checkout with Payment Validation") {
    val customer = lifeline(name = "Customer") { isActor = true }
    val shop     = lifeline(name = "Shop")
    val checkout = lifeline(name = "CheckoutService")
    val gateway  = lifeline(name = "PaymentGateway")
    val db       = lifeline(name = "OrderDB")

    message(from = customer, to = shop, label = "startCheckout()")
    message(from = shop, to = checkout, label = "POST /checkout")
    message(from = checkout, to = gateway, label = "validatePaymentDetails(card)")
    reply(from = gateway, to = checkout, label = "validationResult")

    alt {
        branch(guard = "[payment details valid]") {
            message(from = checkout, to = db, label = "saveOrder(cart)")
            reply(from = db, to = checkout, label = "orderId")
            message(from = checkout, to = gateway, label = "executePayment(amount)")
            reply(from = gateway, to = checkout, label = "paymentConfirmation")
            reply(from = checkout, to = shop, label = "200 OK (orderId)")
        }
        branch(guard = "[payment details invalid]") {
            reply(from = checkout, to = shop, label = "402 Payment Required")
        }
    }
    reply(from = shop, to = customer, label = "resultDisplay")
}

sequenceDiagram(name = "API Rate Limiting with Retry") {
    val client  = lifeline(name = "Client")
    val gateway = lifeline(name = "ApiGateway")
    val limiter = lifeline(name = "RateLimiter")
    val backend = lifeline(name = "BackendService")

    message(from = client, to = gateway, label = "GET /data")
    message(from = gateway, to = limiter, label = "checkLimit(clientId)")
    reply(from = limiter, to = gateway, label = "limitStatus")

    alt {
        branch(guard = "[limit not reached]") {
            message(from = gateway, to = backend, label = "forwardRequest(/data)")
            reply(from = backend, to = gateway, label = "data")
            reply(from = gateway, to = client, label = "200 OK")
        }
        branch(guard = "[limit reached]") {
            reply(from = gateway, to = client, label = "429 Too Many Requests")
        }
    }

    loop(guard = "[response == 429 && attempts < 3]") {
        message(from = client, to = client, label = "waitBackoff()")
        message(from = client, to = gateway, label = "GET /data (Retry)")
        reply(from = gateway, to = client, label = "response")
    }
}

sequenceDiagram(name = "Password Reset Flow") {
    val user   = lifeline(name = "User") { isActor = true }
    val portal = lifeline(name = "WebPortal")
    val auth   = lifeline(name = "AuthService")
    val mail   = lifeline(name = "MailService")
    val db     = lifeline(name = "UserDB")

    message(from = user, to = portal, label = "forgotPassword(email)")
    message(from = portal, to = auth, label = "POST /password-reset")
    message(from = auth, to = db, label = "findUser(email)")
    reply(from = db, to = auth, label = "userRecord")

    alt {
        branch(guard = "[user exists]") {
            message(from = auth, to = auth, label = "generateResetToken()")
            message(from = auth, to = db, label = "storeToken(token, expiry)")
            reply(from = db, to = auth, label = "ok")
            asyncMessage(from = auth, to = mail, label = "sendResetMail(email, token)")
            reply(from = auth, to = portal, label = "200 OK")
        }
        branch(guard = "[user unknown]") {
            reply(from = auth, to = portal, label = "200 OK (identical response)")
        }
    }
    reply(from = portal, to = user, label = "notificationDisplay")
}

sequenceDiagram(name = "Microservice Authentication") {
    val client  = lifeline(name = "Client")
    val gateway = lifeline(name = "ApiGateway")
    val auth    = lifeline(name = "AuthService")
    val cache   = lifeline(name = "TokenCache")
    val order   = lifeline(name = "OrderService")

    message(from = client, to = gateway, label = "GET /orders (JWT)")
    message(from = gateway, to = cache, label = "checkTokenCache(jwt)")
    reply(from = cache, to = gateway, label = "cacheResult")

    opt(guard = "[cache miss]") {
        message(from = gateway, to = auth, label = "validateToken(jwt)")
        reply(from = auth, to = gateway, label = "claims")
        asyncMessage(from = gateway, to = cache, label = "storeValidation(jwt, claims)")
    }

    alt {
        branch(guard = "[token valid]") {
            message(from = gateway, to = order, label = "GET /orders (claims)")
            reply(from = order, to = gateway, label = "orderList")
            reply(from = gateway, to = client, label = "200 OK")
        }
        branch(guard = "[token invalid]") {
            reply(from = gateway, to = client, label = "401 Unauthorized")
        }
    }
}

sequenceDiagram(name = "Distributed Saga Transaction") {
    val customer = lifeline(name = "Customer") { isActor = true }
    val order    = lifeline(name = "OrderService")
    val saga     = lifeline(name = "SagaOrchestrator")
    val warehouse = lifeline(name = "WarehouseService")
    val payment  = lifeline(name = "PaymentService")
    val shipping = lifeline(name = "ShippingService")
    val log      = lifeline(name = "EventLog")

    message(from = customer, to = order, label = "placeOrder(cart)")
    create(from = order, to = saga)
    message(from = order, to = saga, label = "startOrderSaga(order)")
    asyncMessage(from = saga, to = log, label = "log('Saga started')")
    message(from = saga, to = warehouse, label = "reserveItems(positions)")
    reply(from = warehouse, to = saga, label = "reservationResult")

    alt {
        branch(guard = "[items available]") {
            message(from = saga, to = payment, label = "executePayment(amount)")
            reply(from = payment, to = saga, label = "paymentResult")
            alt {
                branch(guard = "[payment successful]") {
                    message(from = saga, to = shipping, label = "commissionShipment(address)")
                    reply(from = shipping, to = saga, label = "trackingNumber")
                    asyncMessage(from = saga, to = log, label = "log('Saga completed')")
                    reply(from = saga, to = order, label = "sagaSuccessful")
                }
                branch(guard = "[payment failed]") {
                    message(from = saga, to = warehouse, label = "cancelReservation(positions)")
                    reply(from = warehouse, to = saga, label = "cancellationConfirmed")
                    asyncMessage(from = saga, to = log, label = "log('Saga compensated')")
                    reply(from = saga, to = order, label = "sagaFailed")
                }
            }
        }
        branch(guard = "[items not available]") {
            asyncMessage(from = saga, to = log, label = "log('Saga aborted')")
            reply(from = saga, to = order, label = "sagaAborted")
        }
    }

    delete(from = order, to = saga)
    reply(from = order, to = customer, label = "orderStatus")
}

sequenceDiagram(name = "Sensor Fusion and Emergency Braking") {
    val camera      = lifeline(name = "CameraSensor")
    val radar       = lifeline(name = "RadarSensor")
    val fusion      = lifeline(name = "FusionUnit")
    val assistant   = lifeline(name = "EmergencyBrakingAssistant")
    val maneuver    = lifeline(name = "BrakingManeuver")
    val controlUnit = lifeline(name = "BrakeControlUnit")
    val hmi         = lifeline(name = "DriverHMI")
    val diagnostic  = lifeline(name = "DiagnosticLog")

    par {
        branch {
            asyncMessage(from = camera, to = fusion, label = "objectList(frame)")
        }
        branch {
            asyncMessage(from = radar, to = fusion, label = "distanceMeasurement(cycle)")
        }
    }

    message(from = fusion, to = fusion, label = "fuseMeasurements()")
    message(from = fusion, to = assistant, label = "reportCollisionRisk(object, ttc)")

    alt {
        branch(guard = "[ttc < 1.5s]") {
            asyncMessage(from = assistant, to = hmi, label = "activateWarningTone()")
            create(from = assistant, to = maneuver)
            message(from = assistant, to = maneuver, label = "start(maxDeceleration)")
            loop(guard = "[obstacle still detected]") {
                message(from = maneuver, to = controlUnit, label = "setBrakePressure(100%)")
                reply(from = controlUnit, to = maneuver, label = "actualDeceleration")
            }
            reply(from = maneuver, to = assistant, label = "vehicleAtStandstill")
            delete(from = assistant, to = maneuver)
            asyncMessage(from = assistant, to = diagnostic, label = "log('Emergency braking executed')")
        }
        branch(guard = "[ttc >= 1.5s]") {
            opt(guard = "[ttc < 3.0s]") {
                asyncMessage(from = assistant, to = hmi, label = "showDistanceWarning()")
            }
            asyncMessage(from = assistant, to = diagnostic, label = "log('Risk observed')")
        }
    }
}

