import dev.kuml.sysml2.dsl.sysml2Model
import dev.kuml.kerml.KermlMultiplicity

sysml2Model(name = "AUTOSAR ECU Architecture") {
    // Hardware
    val cpuCore              = partDef(name = "CPU Core")
    val ram                  = partDef(name = "RAM")
    val flash                = partDef(name = "Flash Memory")
    val commCtrl             = partDef(name = "Communication Controller", isAbstract = true)
    val canCtrl              = partDef(name = "CAN Controller",      specializesId = commCtrl.id)
    val linCtrl              = partDef(name = "LIN Controller",      specializesId = commCtrl.id)
    val ethCtrl              = partDef(name = "Ethernet Controller", specializesId = commCtrl.id)
    val microcontroller      = partDef(name = "Microcontroller") {
        part(name = "cpuCore", typeId = cpuCore.id, multiplicity = KermlMultiplicity.ONE_OR_MORE)
        part(name = "ram",     typeId = ram.id)
        part(name = "flash",   typeId = flash.id)
        part(name = "commCtrl", typeId = commCtrl.id, multiplicity = KermlMultiplicity.ONE_OR_MORE)
    }

    // BSW
    val bswModule        = partDef(name = "BSW Module", isAbstract = true)
    val mcal             = partDef(name = "MCAL Driver Layer",           specializesId = bswModule.id)
    val canStack         = partDef(name = "CAN Communication Stack",      specializesId = bswModule.id)
    val ethStack         = partDef(name = "Ethernet Communication Stack", specializesId = bswModule.id)
    val systemServices   = partDef(name = "System Services (OS/Watchdog)", specializesId = bswModule.id)
    val bswLayer         = partDef(name = "BSW Layer") {
        part(name = "bswModule", typeId = bswModule.id, multiplicity = KermlMultiplicity.ONE_OR_MORE)
    }

    // Application layer
    val swComponent  = partDef(name = "Software Component")
    val vfb          = partDef(name = "Virtual Functional Bus (VFB)")
    val appLayer     = partDef(name = "Application Layer") {
        part(name = "swComponent", typeId = swComponent.id, multiplicity = KermlMultiplicity.ONE_OR_MORE)
        part(name = "vfb",         typeId = vfb.id)
    }

    val ecu = partDef(name = "AUTOSAR ECU") {
        part(name = "microcontroller", typeId = microcontroller.id)
        part(name = "bswLayer",        typeId = bswLayer.id)
        part(name = "appLayer",        typeId = appLayer.id)
    }

    bdd(name = "AUTOSAR ECU BDD") {
        include(ecu)
        include(microcontroller)
        include(cpuCore); include(ram); include(flash); include(commCtrl)
        include(canCtrl); include(linCtrl); include(ethCtrl)
        include(bswLayer); include(bswModule)
        include(mcal); include(canStack); include(ethStack); include(systemServices)
        include(appLayer); include(swComponent); include(vfb)
    }
}

